public class Main {
    public static void main(String[] args) {
        // Autoboxing: int → Integer
        Integer num1 = 100;  // Integer.valueOf(100) is called automatically

        // Unboxing: Integer → int
        int num2 = num1;  // num1.intValue() is called automatically

        // Autoboxing with ArrayList
        java.util.ArrayList<Integer> list = new java.util.ArrayList<>();
        list.add(42);  // int 42 is autoboxed and added as Integer(42)
        int val = list.get(0);  // Unboxed and assigned to val as int

        System.out.println(num1);  // 100
        System.out.println(num2);  // 100
        System.out.println(val);   // 42
    }
}

public class Main {
    public static void main(String[] args) {
        // String → primitive data type
        int a = Integer.parseInt("123");
        double b = Double.parseDouble("3.14");
        boolean c = Boolean.parseBoolean("true");

        // String → wrapper object
        Integer d = Integer.valueOf("456");
        Double e = Double.valueOf("2.71");

        System.out.println(a);  // 123
        System.out.println(b);  // 3.14
        System.out.println(c);  // true
        System.out.println(d);  // 456
        System.out.println(e);  // 2.71

        // NumberFormatException example
        // int f = Integer.parseInt("abc");  // Runtime error
    }
}

