public class Main {
    // Definition of the main method
    public static void main(String[] args) {
        // Variable declaration and initialization
        String s = "Hello Java";

        System.out.println(s.length());       // 10
        System.out.println(s.charAt(0));       // H
        System.out.println(s.charAt(6));       // J
        System.out.println(s.indexOf('J'));    // 6
        System.out.println(s.indexOf("Java")); // 6
        System.out.println(s.indexOf('Z'));    // -1 (when not found)

        // substring(beginIndex) - from beginIndex to the end
        System.out.println(s.substring(6));    // Java
        // substring(beginIndex, endIndex) - from beginIndex to before endIndex
        System.out.println(s.substring(0, 5)); // Hello
    }
}

