public class Main {
    public static void main(String[] args) {
        StringBuilder sb = new StringBuilder("Hello");

        // append: add to the end
        sb.append(" World");
        System.out.println(sb);  // Hello World

        // insert: insert at specified position
        sb.insert(5, ",");
        System.out.println(sb);  // Hello, World

        // delete: delete specified range (beginIndex, endIndex)
        sb.delete(5, 6);
        System.out.println(sb);  // Hello World

        // reverse: reverse the string
        StringBuilder sb2 = new StringBuilder("Java");
        sb2.reverse();
        System.out.println(sb2);  // avaJ

        // length: get the length
        System.out.println(sb.length());  // 11
    }
}

// Definition of the Main class
public class Main {
    // Definition of the main method
    public static void main(String[] args) {
        // Chaining multiple operations with method chaining
        StringBuilder sb = new StringBuilder();
        sb.append("Java").append(" ").append("Silver").insert(0, "★");
        System.out.println(sb);  // ★Java Silver

        // This is equivalent to the following
        StringBuilder sb2 = new StringBuilder();
        sb2.append("Java");
        sb2.append(" ");
        sb2.append("Silver");
        sb2.insert(0, "★");
        System.out.println(sb2);  // ★Java Silver
    }
}

