import java.util.ArrayList;

public class Main {
    public static void main(String[] args) {
        ArrayList<String> list = new ArrayList<>();

        // add: adding elements
        list.add("Java");
        list.add("Python");
        list.add("C++");
        System.out.println(list);  // [Java, Python, C++]

        // get: retrieve by index
        System.out.println(list.get(0));  // Java

        // set: replace element at specified position
        list.set(1, "Ruby");
        System.out.println(list);  // [Java, Ruby, C++]

        // remove: delete element (by index)
        list.remove(2);
        System.out.println(list);  // [Java, Ruby]

        // size: number of elements
        System.out.println(list.size());  // 2
    }
}

import java.util.ArrayList;

public class Main {
    public static void main(String[] args) {
        ArrayList<String> fruits = new ArrayList<>();
        fruits.add("Apple");
        fruits.add("Banana");
        fruits.add("Cherry");

        // Enhanced for loop
        for (String fruit : fruits) {
            System.out.println(fruit);
        }
        // Apple
        // Banana
        // Cherry

        // Regular for loop (with index)
        for (int i = 0; i < fruits.size(); i++) {
            System.out.println(i + ": " + fruits.get(i));
        }
        // 0: Apple
        // 1: Banana
        // 2: Cherry
    }
}

